import { useState, useEffect, useRef } from "react";

// ── 串接 Google Sheets：把這裡換成你的 Apps Script 網址 ──
const GOOGLE_SCRIPT_URL = "YOUR_GOOGLE_APPS_SCRIPT_URL";

const POSTER = "data:image/jpeg;base64,";
const MAPS_URL = "https://maps.app.goo.gl/XgQ6QkWc1v2xzM7y6";

// ── 粒子背景 ──
function Particles() {
  const canvasRef = useRef(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    let W = canvas.width = canvas.offsetWidth;
    let H = canvas.height = canvas.offsetHeight;
    const particles = Array.from({ length: 55 }, () => ({
      x: Math.random() * W, y: Math.random() * H,
      r: 1 + Math.random() * 2.5,
      dx: (Math.random() - 0.5) * 0.35,
      dy: -0.2 - Math.random() * 0.4,
      o: 0.1 + Math.random() * 0.55,
      hue: 330 + Math.random() * 40,
    }));
    let raf;
    const draw = () => {
      ctx.clearRect(0, 0, W, H);
      particles.forEach(p => {
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fillStyle = `hsla(${p.hue},80%,80%,${p.o})`;
        ctx.fill();
        p.x += p.dx; p.y += p.dy;
        if (p.y < -4) { p.y = H + 4; p.x = Math.random() * W; }
        if (p.x < 0) p.x = W; if (p.x > W) p.x = 0;
      });
      raf = requestAnimationFrame(draw);
    };
    draw();
    return () => cancelAnimationFrame(raf);
  }, []);
  return <canvas ref={canvasRef} style={{ position:"fixed", inset:0, width:"100%", height:"100%", pointerEvents:"none", zIndex:0 }} />;
}

export default function KTVRegistration() {
  const [status, setStatus] = useState("idle");
  const [form, setForm] = useState({
    name: "", email: "", ig: "", remit: "", notes: ""
  });

  useEffect(() => {
    const style = document.createElement("style");
    style.textContent = `
      @import url('https://fonts.googleapis.com/css2?family=Noto+Serif+TC:wght@400;500;700;900&display=swap');
      *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
      body { background: #1a0010; }
      @keyframes floatIn { from{opacity:0;transform:translateY(32px);} to{opacity:1;transform:translateY(0);} }
      @keyframes shimmer {
        0%{background-position:200% center;}
        100%{background-position:-200% center;}
      }
      @keyframes rosePulse {
        0%,100%{box-shadow:0 0 0 0 rgba(220,100,150,0.0),0 20px 60px rgba(180,40,80,0.35);}
        50%{box-shadow:0 0 0 6px rgba(220,100,150,0.08),0 20px 70px rgba(200,60,100,0.5);}
      }
      input::placeholder,textarea::placeholder{color:rgba(255,180,210,0.35);}
      input:focus,textarea:focus,select:focus{
        outline:none;
        border-color:rgba(255,160,200,0.6)!important;
        box-shadow:0 0 0 3px rgba(220,80,130,0.15)!important;
      }
      select option{background:#2a0515;color:#ffd0e8;}
      .submit-btn:not(:disabled):hover{
        filter:brightness(1.12);
        transform:translateY(-2px) scale(1.01);
      }
      .submit-btn:not(:disabled):active{transform:translateY(0) scale(0.99);}
      .addr-link:hover{text-decoration:underline!important;opacity:0.85;}
    `;
    document.head.appendChild(style);
    return () => document.head.removeChild(style);
  }, []);

  const update = f => e => setForm(p => ({ ...p, [f]: e.target.value }));

  const handleSubmit = async () => {
    if (!form.name || !form.email) return;
    setStatus("loading");
    try {
      await fetch(GOOGLE_SCRIPT_URL, {
        method: "POST", mode: "no-cors",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...form, timestamp: new Date().toISOString() }),
      });
      setStatus("success");
    } catch { setStatus("error"); }
  };

  const reset = () => {
    setForm({ name:"", email:"", ig:"", remit:"", notes:"" });
    setStatus("idle");
  };

  // ── 成功畫面 ──
  if (status === "success") return (
    <div style={s.page}>
      <Particles />
      <div style={{ ...s.card, animation:"floatIn 0.6s ease forwards", padding:"0 0 40px" }}>
        <img src={POSTER} alt="活動海報" style={s.posterImg} />
        <div style={{ padding:"32px 28px 0", textAlign:"center" }}>
          <div style={s.goldTitle}>報名成功</div>
          <p style={s.successSub}>
            {form.name}，不見不散！<br/>
            6 / 18（四）19:00
          </p>
          <a href={MAPS_URL} target="_blank" rel="noopener noreferrer"
            style={{ ...s.addrLink, display:"block", marginBottom:24 }}
            className="addr-link">
            錢櫃忠孝店・忠孝東路四段22號
          </a>
          <div style={s.payBox}>
            <div style={s.payTitle}>請完成匯款</div>
            <div style={s.payAmt}>NT$ 500 / 人</div>
            <div style={s.payBank}>郵局（700）</div>
            <div style={s.payAcc}>0311248-0293927</div>
            <div style={s.payHint}>請於 6/16（二）18:00 前完成匯款</div>
          </div>
          <button style={{ ...s.submitBtn, marginTop:24 }} onClick={reset}>幫姐妹也報名</button>
        </div>
      </div>
    </div>
  );

  // ── 主表單 ──
  return (
    <div style={s.page}>
      <Particles />
      <div style={{ ...s.card, animation:"floatIn 0.8s ease forwards" }}>

        {/* 海報 */}
        <img src={POSTER} alt="大人女子会 KTV之夜" style={s.posterImg} />

        {/* 活動資訊 */}
        <div style={s.infoSection}>
          <div style={s.infoRow}>
            <div style={{ textAlign:"center" }}>
              <div style={s.infoDate}>6 / 18</div>
              <div style={s.infoSmall}>星期四 19:00</div>
            </div>
            <div style={s.infoDividerDot} />
            <div style={{ textAlign:"center" }}>
              <div style={s.infoVenue}>錢櫃忠孝店</div>
              <a href={MAPS_URL} target="_blank" rel="noopener noreferrer"
                style={s.addrLink} className="addr-link">
                忠孝東路四段22號 ↗
              </a>
            </div>
          </div>
          <div style={s.deadlinePill}>報名期限：6/16（二）18:00 截止</div>
        </div>

        {/* 訂金說明 */}
        <div style={s.payBox}>
          <div style={s.payTitle}>需預付訂金 500 元</div>
          <div style={s.payDesc}>現場活動結束後重新結算費用，並直接扣除此訂金</div>
          <div style={s.payBank}>郵局（700）</div>
          <div style={s.payAcc}>0311248-0293927</div>
        </div>

        {/* 分隔 */}
        <div style={s.dividerRow}>
          <span style={s.dividerLine} />
          <span style={s.dividerLabel}>報名填寫</span>
          <span style={s.dividerLine} />
        </div>

        {/* 欄位 */}
        <div style={s.formBody}>

          <Field label="怎麼稱呼妳" required value={form.name}
            onChange={update("name")} placeholder="請輸入妳的稱呼" />

          <Field label="mail" required value={form.email}
            onChange={update("email")} placeholder="example@email.com" type="email"
            hint="匯款成功後將寄送確認信至此信箱" />

          <Field label="Instagram ID" value={form.ig}
            onChange={update("ig")} placeholder="@username" />

          <Field label="匯款後五碼" value={form.remit}
            onChange={update("remit")} placeholder="請輸入匯款帳號後 5 碼" />

          <div style={s.fieldGroup}>
            <label style={s.label}>備註說明</label>
            <textarea value={form.notes} onChange={update("notes")}
              placeholder="其他備註..." rows={3}
              style={{ ...s.input, resize:"vertical" }} />
            <div style={s.fieldHint}>若需取消，請於活動前一天告知</div>
          </div>

          <button className="submit-btn" onClick={handleSubmit}
            disabled={!form.name || !form.email || status === "loading"}
            style={{
              ...s.submitBtn,
              opacity: (!form.name || !form.email) ? 0.4 : 1,
              cursor: (!form.name || !form.email) ? "not-allowed" : "pointer",
            }}>
            {status === "loading" ? "送出中..." : "不見不散 ✦ 確認送出"}
          </button>

          {status === "error" && (
            <p style={{ textAlign:"center", color:"#ffaacc", fontSize:12 }}>
              送出失敗，請稍後再試
            </p>
          )}
        </div>
      </div>
    </div>
  );
}

function Field({ label, required, value, onChange, placeholder, type="text", hint }) {
  return (
    <div style={s.fieldGroup}>
      <label style={s.label}>
        {label}{required && <span style={{ color:"#ffaac8", marginLeft:3 }}>*</span>}
      </label>
      <input type={type} value={value} onChange={onChange}
        placeholder={placeholder} style={s.input} />
      {hint && <div style={s.fieldHint}>{hint}</div>}
    </div>
  );
}

function SelectField({ label, value, onChange, options }) {
  return (
    <div style={s.fieldGroup}>
      <label style={s.label}>{label}</label>
      <select value={value} onChange={onChange} style={s.input}>
        {options.map(o => <option key={o} value={o}>{o}</option>)}
      </select>
    </div>
  );
}

